onClick:
{{
  const pass = (inp_delete_pass.text || "").trim();

  // TODO: en la siguiente iteración reemplazamos esto por validación real (tabla usuarios / rol / hash)
  if (pass !== "TU_PASSWORD") {
    showAlert("Contraseña incorrecta.", "error");
    return;
  }

  bk_delete_booking.run()
    .then(() => {
      closeModal("mdlDeleteBooking");
      showAlert("Registro eliminado.", "success");

      storeValue("booking_id", null);
      storeValue("booking_mode", "VIEW");
      storeValue("operacion_no_preview", "");
      resetWidget("cntBookingForm", true);
    })
    .catch(() => showAlert("Error eliminando.", "error"));
}}
